CREATE OR REPLACE FUNCTION fpa_fin_vourcher_name (as_bank_fin char,as_book_no char,as_cheque_no char , as_paid_info char) RETURNS varchar AS $body$
DECLARE

  ls_return varchar(200);
  ldc_amount bigint;
  ls_grp_name varchar(100);
  li_count integer;
  li_count_item integer;
  ls_paid_name sc_fin_cheque_print.paid_name%type;
  ls_vourcher_name varchar(200);
  type tabrowi_chq_item is table of sc_fin_cheque_print_item%rowtype index by integer;ltabrowi_chq_item tabrowi_chq_item;




BEGIN
  --หาเชคว่าเป็นเชคเดี่ยวหรือเชคกลุ่ม
  begin
    select  count(book_no) into STRICT li_count_item
    from  sc_fin_cheque_print_item
    where (bank_fin = as_bank_fin)
    and (book_no = as_book_no)
    and (cheque_no = as_cheque_no);
  exception
  when no_data_found then  null;
  when others then CALL spa_dberror('select  bulk collect');return null;
  end;


  if li_count_item > 1 then
     ls_return := '1';
  else
     ls_return := '0';
  end if;
  if ls_return = '0' then
  --
   begin
    select  sc_fin_cheque_print.paid_name
        ,   sc_fin_vourcher_head.vourcher_name

    into STRICT    ls_paid_name
        ,   ls_vourcher_name

    from    sc_fin_cheque_print
        ,   sc_fin_cheque_print_item
        ,   sc_fin_vourcher_head

    where (sc_fin_cheque_print.cheque_no = sc_fin_cheque_print_item.cheque_no )
    and (sc_fin_cheque_print.bank_fin = sc_fin_cheque_print_item.bank_fin )
    and (sc_fin_cheque_print.book_no = sc_fin_cheque_print_item.book_no )
    and (sc_fin_cheque_print.seq_no = sc_fin_cheque_print_item.seq_no)
    and (sc_fin_vourcher_head.vourcher_no = sc_fin_cheque_print_item.vourcher_no)
    and (sc_fin_cheque_print.cheque_no = as_cheque_no);
    exception when  others then CALL spa_dberror('ไม่พบเช็คเลขที่ '||trim(both as_cheque_no));return null;
   end;
  --
    if trim(both ls_paid_name) <> trim(both ls_vourcher_name) then
       ls_return := '1';
    end if;
  end if;
  begin
   select loan_approve_amount , FPA_COM_GROUP_INITIAL(trim(both pka_com_function.fp_get_member_group(membership_no)))
   into STRICT   ldc_amount          , ls_grp_name
   from   sc_lon_m_contract
   where  (trim(both loan_contract_no) = (
          SELECT  trim(both ref_docno)
          from    sc_fin_vourcher_head
          where (vourcher_no = as_paid_info)
          ));
  exception when others then CALL spa_dberror('select  sc_lon_m_contract');
  end;
  ls_return := trim(both ls_return)||'   '||trim(both to_char(ldc_amount,'999,999,999.99'))||'  '||trim(both ls_grp_name);

return ls_return;
exception when others then CALL spa_dberror('FPA_FIN_VOURCHER_NAME'||as_paid_info);return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
